import { app, BrowserWindow, ipcMain } from 'electron';
import path from 'path';
import fs from 'fs';
import {
  IPC_CHANNELS,
  CreateTerminalSchema,
  TerminalInputSchema,
  TerminalResizeSchema,
  OpenTerminalWindowSchema,
  type ApiResult,
} from './types';
import { terminalService } from '../services/TerminalService';

const CloseTerminalSchema = TerminalInputSchema.pick({ sessionId: true });

const isDev = !app.isPackaged && process.env.NODE_ENV !== 'production';

const resolveRendererEntry = () => {
  const appPath = app.getAppPath();
  const candidates = [
    { path: path.resolve(__dirname, '..', '..', 'dist-renderer', 'index.html'), source: 'relative-to-main' as const },
    { path: path.join(appPath, 'dist-renderer', 'index.html'), source: 'app-root' as const },
    { path: path.join(process.resourcesPath, 'dist-renderer', 'index.html'), source: 'resources-root' as const },
  ];

  for (const candidate of candidates) {
    if (fs.existsSync(candidate.path)) {
      return candidate;
    }
  }

  return candidates[0];
};

export function registerTerminalHandlers() {
  ipcMain.handle(IPC_CHANNELS.TERMINAL_CREATE, async (event, rawInput): Promise<ApiResult<{ sessionId: string }>> => {
    try {
      const input = CreateTerminalSchema.parse(rawInput);
      const window = BrowserWindow.fromWebContents(event.sender);
      if (!window) {
        throw new Error('Unable to resolve renderer window for terminal session.');
      }

      const result = await terminalService.createSession({
        serverId: input.serverId,
        cols: input.cols,
        rows: input.rows,
        webContentsId: event.sender.id,
      });

      return { success: true, data: result };
    } catch (error) {
      console.error('[Terminal] Failed to create session:', error);
      return { success: false, error: error instanceof Error ? error.message : String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.TERMINAL_INPUT, async (_event, rawInput): Promise<ApiResult<void>> => {
    try {
      const input = TerminalInputSchema.parse(rawInput);
      await terminalService.write(input.sessionId, input.data);
      return { success: true };
    } catch (error) {
      console.error('[Terminal] Failed to forward input:', error);
      return { success: false, error: error instanceof Error ? error.message : String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.TERMINAL_RESIZE, async (_event, rawInput): Promise<ApiResult<void>> => {
    try {
      const input = TerminalResizeSchema.parse(rawInput);
      await terminalService.resize(input.sessionId, input.cols, input.rows);
      return { success: true };
    } catch (error) {
      console.error('[Terminal] Failed to resize session:', error);
      return { success: false, error: error instanceof Error ? error.message : String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.TERMINAL_CLOSE, async (_event, rawInput): Promise<ApiResult<void>> => {
    try {
      const input = CloseTerminalSchema.parse(rawInput);
      await terminalService.close(input.sessionId);
      return { success: true };
    } catch (error) {
      console.error('[Terminal] Failed to close session:', error);
      return { success: false, error: error instanceof Error ? error.message : String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.TERMINAL_OPEN_WINDOW, async (_event, rawInput): Promise<ApiResult<{ windowId: number }>> => {
    try {
      const input = OpenTerminalWindowSchema.parse(rawInput);
      const { serverId, serverName, initialCommand } = input;

      const terminalWindow = new BrowserWindow({
        width: 900,
        height: 600,
        minWidth: 600,
        minHeight: 400,
        title: serverName ? `Terminal - ${serverName}` : 'Terminal',
        webPreferences: {
          preload: path.join(__dirname, '../preload.js'),
          contextIsolation: true,
          nodeIntegration: false,
          sandbox: false,
        },
        titleBarStyle: process.platform === 'darwin' ? 'hiddenInset' : 'default',
        show: false,
      });

      terminalWindow.once('ready-to-show', () => {
        terminalWindow.show();
      });

      const devServerURL = process.env.VITE_DEV_SERVER_URL ?? 'http://localhost:5173';
      const { path: rendererIndexPath } = resolveRendererEntry();

      const queryParams = new URLSearchParams({
        serverId,
        serverName: serverName || '',
        ...(initialCommand ? { initialCommand } : {}),
      });

      if (isDev) {
        await terminalWindow.loadURL(`${devServerURL}#/terminal-window?${queryParams.toString()}`);
      } else {
        await terminalWindow.loadFile(rendererIndexPath, {
          hash: `/terminal-window?${queryParams.toString()}`,
        });
      }

      return { success: true, data: { windowId: terminalWindow.id } };
    } catch (error) {
      console.error('[Terminal] Failed to open terminal window:', error);
      return { success: false, error: error instanceof Error ? error.message : String(error) };
    }
  });
}
